import { 
  Camera, 
  Upload, 
  Sparkles, 
  Copy, 
  Check, 
  Languages, 
  RefreshCw, 
  Image as ImageIcon,
  Trash2,
  X,
  Plus
} from 'lucide-react';

const gemini = new GeminiService();

