  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    Array.from(files).forEach(file => {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImages(prev => [...prev, reader.result as string]);
      };
      reader.readAsDataURL(file);
    });
  };

  const removeImage = (index: number) => {
    setImages(prev => prev.filter((_, i) => i !== index));
  };

  const analyzeImages = async () => {
    if (images.length === 0) return;
    setIsAnalyzing(true);
    try {
      const desc = await gemini.analyzeImages(images);
      setDescription(desc);
    } catch (error) {
      console.error("Analysis failed", error);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const generatePrompt = async () => {
    if (!description) return;
    setIsGenerating(true);
    try {
      const promptData = await gemini.generateStoryboardPrompt(
        description,
        shots.map(type => ({ type, description: "" }))
      );
      setGeneratedPrompt(promptData);
    } catch (error) {
      console.error("Generation failed", error);
    } finally {
      setIsGenerating(false);
    }
  };

  const copyToClipboard = () => {
    if (!generatedPrompt) return;
    const text = language === 'english' ? generatedPrompt.english : generatedPrompt.chinese;
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const updateShot = (index: number, type: ShotType) => {
    const newShots = [...shots];
    newShots[index] = type;
    setShots(newShots);
  };

  return (
    <div className="flex flex-col md:flex-row h-screen overflow-hidden">
      {/* Sidebar: Controls */}
      <aside className="w-full md:w-[400px] bg-zinc-950 border-r border-zinc-800 flex flex-col overflow-y-auto p-6 gap-8">
        <header className="flex items-center gap-3">
          <div className="bg-blue-600 p-2 rounded-xl">
            <Sparkles className="text-white" size={20} />
          </div>
          <h1 className="text-xl font-bold bg-gradient-to-r from-white to-zinc-400 bg-clip-text text-transparent">
            Storyboard Grid Pro
          </h1>
        </header>

        {/* 1. Reference Images */}
        <section className="space-y-4">
          <div className="flex items-center justify-between">
            <h2 className="text-sm font-semibold text-zinc-400 flex items-center gap-2">
              <ImageIcon size={16} /> Reference Images
            </h2>
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="text-xs text-blue-500 hover:text-blue-400 font-medium transition-colors"
            >
              Add Images
            </button>
          </div>

          <div className="grid grid-cols-3 gap-2">
            {images.map((img, idx) => (
