                  className="absolute top-1 right-1 p-1 bg-black/60 rounded-md opacity-0 group-hover:opacity-100 transition-opacity hover:bg-red-500/80"
                >
                  <X size={12} />
                </button>
              </div>
            ))}
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="aspect-square rounded-lg border-2 border-dashed border-zinc-800 flex flex-col items-center justify-center gap-1 text-zinc-600 hover:border-zinc-600 hover:text-zinc-400 transition-all"
            >
