              <p className="text-zinc-500 text-sm mt-1">Consistency-tuned storyboard prompts for high-end AI imaging.</p>
            </div>

            <div className="flex items-center gap-2 bg-zinc-950 p-1 rounded-lg border border-zinc-800">
              <button 
                onClick={() => setLanguage('english')}
                className={`px-3 py-1.5 rounded-md text-xs font-medium transition-all ${language === 'english' ? 'bg-zinc-800 text-white' : 'text-zinc-500 hover:text-zinc-300'}`}
              >
                English
              </button>
              <button 
                onClick={() => setLanguage('chinese')}
                className={`px-3 py-1.5 rounded-md text-xs font-medium transition-all ${language === 'chinese' ? 'bg-zinc-800 text-white' : 'text-zinc-500 hover:text-zinc-300'}`}
