              <div className="p-4 bg-zinc-950 rounded-2xl">
                <Sparkles size={40} className="text-zinc-800" />
              </div>
              <p className="text-lg">Your cinematic prompt will appear here</p>
              <p className="text-sm max-w-xs text-center opacity-60">Complete the steps in the sidebar to generate a 9-shot consistent grid prompt.</p>
            </div>
          ) : isGenerating ? (
            <div className="h-[500px] flex flex-col items-center justify-center gap-6">
              <div className="relative">
                <div className="w-16 h-16 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                <div className="absolute inset-0 flex items-center justify-center">
                  <Sparkles size={20} className="text-blue-500" />
