                  <div className="flex gap-4">
                    <span>9 SLOTS DETECTED</span>
                    <span>16:9 AR</span>
                    <span>8K RES</span>
                  </div>
                  <div className="flex items-center gap-1">
                    <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></div>
                    READY FOR MIDJOURNEY / FLUX
                  </div>
                </div>
              </div>
            </div>
          )}

          {/* Quick Tips */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div className="p-4 bg-zinc-950 rounded-xl border border-zinc-800 space-y-2">
              <h4 className="text-xs font-bold text-zinc-400 uppercase tracking-wider">Consistency Tip</h4>
              <p className="text-xs text-zinc-500 leading-relaxed">Reverse engineering the image creates 'visual tokens' that ensure the AI keeps the same face and clothes across all 9 grid tiles.</p>
            </div>
            <div className="p-4 bg-zinc-950 rounded-xl border border-zinc-800 space-y-2">
              <h4 className="text-xs font-bold text-zinc-400 uppercase tracking-wider">Grid Formatting</h4>
              <p className="text-xs text-zinc-500 leading-relaxed">The [3x3] grid prompt structure is optimized for models like Midjourney and Flux to generate multiple viewpoints simultaneously.</p>
            </div>
            <div className="p-4 bg-zinc-950 rounded-xl border border-zinc-800 space-y-2">
              <h4 className="text-xs font-bold text-zinc-400 uppercase tracking-wider">Prompt Engineering</h4>
              <p className="text-xs text-zinc-500 leading-relaxed">Language toggles allow you to use English for the generator engine while maintaining clear Chinese instructions for your records.</p>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
}

import { GoogleGenAI, Type } from "@google/genai";
import { StoryboardShot, GeneratedPrompt } from "../types";

const MODEL_NAME = 'gemini-3-flash-preview';

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    // Guidelines: Must use new GoogleGenAI({ apiKey: process.env.API_KEY }) directly
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  /**
   * Analyzes uploaded images to extract character/scene details.
   */
  async analyzeImages(imageB64s: string[]): Promise<string> {
    const parts = imageB64s.map(data => ({
      inlineData: {
        mimeType: 'image/jpeg',
        data: data.split(',')[1] || data,
      },
    }));

    const response = await this.ai.models.generateContent({
      model: MODEL_NAME,
      contents: {
        parts: [
          ...parts,
          { text: "Analyze these reference images. Provide a very detailed physical description of the main subject (person/object), their clothing, materials, facial features, and the lighting/environment. This description will be used as a base for AI image generation consistency. Focus on 'visual tokens' like specific colors, textures, and styles. Output only the description." }
        ]
      },
    });

    return response.text || "Could not analyze image.";
  }

  /**
   * Generates the structured storyboard prompt in both EN and CN.
   */
  async generateStoryboardPrompt(
    baseDescription: string, 
    shots: { type: string, description: string }[]
  ): Promise<GeneratedPrompt> {
    const response = await this.ai.models.generateContent({
      model: MODEL_NAME,
      contents: `
        Base Character/Scene Description: ${baseDescription}

        Selected Camera Shots for 3x3 Grid:
        ${shots.map((s, i) => `Shot ${i + 1}: ${s.type}`).join('\n')}

        TASK: Create a professional AI image generation prompt for a 3x3 grid. 
        The prompt must follow this structure exactly:
        "Based on [detailed base description], generate a cohesive [3x3] grid image, containing [9] different camera shots in the same environment, strictly maintaining character/object, clothing and lighting consistency, [8K] resolution, [16:9] aspect ratio.
        Shot 01: [Brief visual description focusing on the shot type and consistency]
        Shot 02: ...
        ...
        Shot 09: ..."

        Return the result in JSON format with 'english' and 'chinese' keys.
      `,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            english: { type: Type.STRING },
            chinese: { type: Type.STRING }
          },
          required: ["english", "chinese"]
        }
      }
    });

    try {
      // response.text is a property, not a method call
      return JSON.parse(response.text || '{}');
    } catch (e) {
      return { 
        english: response.text || "Error generating EN prompt", 
        chinese: "无法生成中文提示词" 
      };
    }
  }
}

