          </div>
        </div>
      </main>

      {/* Camera Modal */}
      {isCameraOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-zinc-950/90 backdrop-blur-sm p-4">
          <div className="bg-zinc-900 rounded-[32px] border border-zinc-800 overflow-hidden max-w-lg w-full shadow-2xl animate-in zoom-in-95 duration-300">
            <div className="p-6 border-b border-zinc-800 flex items-center justify-between">
              <h3 className="text-lg font-bold text-white flex items-center gap-2">
                <Camera className="text-blue-500" /> Reference Snapshot
              </h3>
              <button onClick={stopCamera} className="p-2 text-zinc-500 hover:text-white transition-colors">
                <X size={20} />
              </button>
            </div>
            <div className="relative aspect-[4/3] bg-black">
              <video 
                ref={videoRef} 
                autoPlay 
                playsInline 
                className="w-full h-full object-cover mirror"
              />
              <div className="absolute inset-0 flex items-center justify-center pointer-events-none opacity-20 border-4 border-white/20 m-8 rounded-2xl">
              </div>
