import { GoogleGenAI, Type } from "@google/genai";
import { StoryboardShot, GeneratedPrompt } from "../types";

const MODEL_NAME = 'gemini-3-flash-preview';

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  /**
   * Analyzes uploaded images to extract character/scene details.
   */
  async analyzeImages(imageB64s: string[]): Promise<string> {
    const parts = imageB64s.map(data => ({
      inlineData: {
        mimeType: 'image/jpeg',
        data: data.split(',')[1] || data,
      },
    }));

    const response = await this.ai.models.generateContent({
      model: MODEL_NAME,
      contents: {
        parts: [
          ...parts,
          { text: "Analyze these reference images. Provide a very detailed physical description of the main subject (person/object), their clothing, materials, facial features, and the lighting/environment. This description will be used as a base for AI image generation consistency. Focus on 'visual tokens' like specific colors, textures, and styles. Output only the description." }
        ]
      },
    });

    return response.text || "Could not analyze image.";
  }

  /**
   * Generates the structured storyboard prompt in both EN and CN.
   */
  async generateStoryboardPrompt(
    baseDescription: string, 
    shots: { type: string, description: string }[]
  ): Promise<GeneratedPrompt> {
    const response = await this.ai.models.generateContent({
      model: MODEL_NAME,
      contents: `
        Base Character/Scene Description: ${baseDescription}

        Selected Camera Shots for 3x3 Grid:
        ${shots.map((s, i) => `Shot ${i + 1}: ${s.type}`).join('\n')}

        TASK: Create a professional, highly structured AI image generation prompt for a 3x3 grid in both English and Chinese.

        ENHANCEMENT RULES:
        1. Use clear visual headers (e.g., [CORE PARAMETERS], [SHOT SEQUENCE]).
        2. Use "markdown-like" emphasis (**TEXT**) for key terms like character features, shot types, and technical specs.
        3. Use line separators (--- or ===) to organize sections.
        4. Ensure the character consistency details are woven into EVERY shot description.

        English Version Format:
        "[CORE PARAMETERS]
        Style: Cinematic 8K, 16:9 Aspect Ratio.
        Base: [detailed description with **emphasized tokens**]

        --------------------------------------------------
        [3x3 GRID SHOT SEQUENCE]
        --------------------------------------------------
        **Shot 01:** [Shot Type] - [Action/Description focusing on consistency]
        **Shot 02:** ...
        ...
        **Shot 09:** ...

        [TECHNICAL SPECIFICATIONS]
        Grid: 3x3, Resolution: 8K, Consistency Level: Maximum."

        Chinese Version Format (STRICTLY FOLLOW THIS BASE BUT ADD ENHANCEMENTS):
        "[核心场景参数]
        画幅: 16:9, 分辨率: 8K 高清
        描述: [详细场景内容，使用 **加粗** 强调关键特征]

        --------------------------------------------------
        [3x3 分镜细节序列]
        --------------------------------------------------
        **镜头 01:** [景别] - [描述内容，强调光影与角色一致性]
        **镜头 02:** ...
        ...
        **镜头 09:** ...

        [生成配置]
        布局: 3x3 网格, 严格保持人物、服装、环境凝聚力。"

        Return the result in JSON format with 'english' and 'chinese' keys.
      `,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            english: { type: Type.STRING },
            chinese: { type: Type.STRING }
          },
          required: ["english", "chinese"]
        }
      }
    });

    try {
      return JSON.parse(response.text || '{}');
    } catch (e) {
      return { 
        english: response.text || "Error generating EN prompt", 
        chinese: "无法生成中文提示词" 
      };
    }
  }
}

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { GeminiService } from './services/geminiService';
import { ShotType, GeneratedPrompt } from './types';
import { DEFAULT_SHOTS } from './constants';
import { ShotSelector } from './components/ShotSelector';
import { 
  Camera, 
  Sparkles, 
  Copy, 
  Check, 
  RefreshCw, 
  Image as ImageIcon,
  X,
  Plus,
  Trash2,
  ChevronRight,
  Info,
  Zap,
  HelpCircle
} from 'lucide-react';

const gemini = new GeminiService();

/**
 * Reusable Tooltip Component for UI guidance
 */
const Tooltip = ({ children, content, position = 'top' }: { children: React.ReactNode, content: string, position?: 'top' | 'bottom' | 'left' | 'right' }) => {
  const [show, setShow] = useState(false);

  const positions = {
    top: "bottom-full mb-2 left-1/2 -translate-x-1/2",
    bottom: "top-full mt-2 left-1/2 -translate-x-1/2",
    left: "right-full mr-2 top-1/2 -translate-y-1/2",
    right: "left-full ml-2 top-1/2 -translate-y-1/2"
  };

  const arrows = {
    top: "top-full left-1/2 -translate-x-1/2 border-t-zinc-800",
    bottom: "bottom-full left-1/2 -translate-x-1/2 border-b-zinc-800",
    left: "left-full top-1/2 -translate-y-1/2 border-l-zinc-800",
    right: "right-full top-1/2 -translate-y-1/2 border-r-zinc-800"
  };

  return (
    <div className="relative inline-flex items-center" onMouseEnter={() => setShow(true)} onMouseLeave={() => setShow(false)}>
      {children}
      {show && (
        <div className={`absolute ${positions[position]} px-3 py-1.5 bg-zinc-800 text-zinc-100 text-[10px] font-medium rounded-lg shadow-2xl whitespace-nowrap z-[100] pointer-events-none border border-zinc-700 animate-in fade-in zoom-in-95 duration-200`}>
          {content}
          <div className={`absolute border-4 border-transparent ${arrows[position]}`}></div>
        </div>
      )}
    </div>
  );
};

export default function App() {
  const [images, setImages] = useState<string[]>([]);
  const [description, setDescription] = useState('');
  const [shots, setShots] = useState<ShotType[]>(DEFAULT_SHOTS);
  const [generatedPrompt, setGeneratedPrompt] = useState<GeneratedPrompt | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [language, setLanguage] = useState<'english' | 'chinese'>('english');
  const [copied, setCopied] = useState(false);
  const [isCameraOpen, setIsCameraOpen] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    Array.from(files).forEach((file: File) => {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImages(prev => [...prev, reader.result as string].slice(0, 5));
      };
      reader.readAsDataURL(file);
    });
    e.target.value = '';
  };

  const removeImage = (index: number) => {
    setImages(prev => prev.filter((_, i) => i !== index));
  };

  const clearAll = () => {
    if (confirm('Clear everything?')) {
      setImages([]);
      setDescription('');
      setGeneratedPrompt(null);
      setShots(DEFAULT_SHOTS);
    }
  };

  const startCamera = async () => {
    setIsCameraOpen(true);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'user' },
        audio: false 
      });
      streamRef.current = stream;
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
    } catch (err) {
      console.error("Camera access denied", err);
      setIsCameraOpen(false);
      alert("Could not access camera. Please check permissions.");
    }
  };

  const stopCamera = () => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    setIsCameraOpen(false);
  };

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        const dataUrl = canvas.toDataURL('image/jpeg');
        setImages(prev => [...prev, dataUrl].slice(0, 5));
        stopCamera();
      }
    }
  };

  const analyzeImages = async () => {
    if (images.length === 0) return;
    setIsAnalyzing(true);
    try {
      const desc = await gemini.analyzeImages(images);
      setDescription(desc);
    } catch (error) {
      console.error("Analysis failed", error);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const generatePrompt = async () => {
    if (!description) return;
    setIsGenerating(true);
    try {
      const promptData = await gemini.generateStoryboardPrompt(
        description,
        shots.map(type => ({ type, description: "" }))
      );
      setGeneratedPrompt(promptData);
    } catch (error) {
      console.error("Generation failed", error);
    } finally {
      setIsGenerating(false);
    }
  };

  const copyToClipboard = () => {
    if (!generatedPrompt) return;
    const text = language === 'english' ? generatedPrompt.english : generatedPrompt.chinese;
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const updateShot = (index: number, type: ShotType) => {
    const newShots = [...shots];
    newShots[index] = type;
    setShots(newShots);
  };

