                    <div className="flex items-center gap-2 px-3 py-1.5 bg-green-500/5 border border-green-500/20 rounded-lg">
                      <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></div>
                      <span className="text-[10px] font-black text-green-500/80 tracking-widest uppercase">Verified Consistent</span>
                    </div>
                  </div>
                </div>
