import React, { useState, useCallback, useRef, useEffect } from 'react';
import { GeminiService } from './services/geminiService';
import { ShotType, GeneratedPrompt, StoryboardShot } from './types';
import { DEFAULT_SHOTS } from './constants';
import { ShotSelector } from './components/ShotSelector';
import { 
  Camera, 
  Sparkles, 
  Copy, 
  Check, 
  RefreshCw, 
  Image as ImageIcon,
  X,
  Plus,
  Trash2,
  ChevronRight,
  Info,
  Zap,
  HelpCircle
} from 'lucide-react';

const gemini = new GeminiService();

/**
 * Reusable Tooltip Component for UI guidance
 */
const Tooltip = ({ children, content, position = 'top' }: { children: React.ReactNode, content: string, position?: 'top' | 'bottom' | 'left' | 'right' }) => {
  const [show, setShow] = useState(false);

  const positions = {
    top: "bottom-full mb-2 left-1/2 -translate-x-1/2",
    bottom: "top-full mt-2 left-1/2 -translate-x-1/2",
    left: "right-full mr-2 top-1/2 -translate-y-1/2",
    right: "left-full ml-2 top-1/2 -translate-y-1/2"
  };

  const arrows = {
    top: "top-full left-1/2 -translate-x-1/2 border-t-zinc-800",
    bottom: "bottom-full left-1/2 -translate-x-1/2 border-b-zinc-800",
    left: "left-full top-1/2 -translate-y-1/2 border-l-zinc-800",
    right: "right-full top-1/2 -translate-y-1/2 border-r-zinc-800"
  };

  return (
    <div className="relative inline-flex items-center" onMouseEnter={() => setShow(true)} onMouseLeave={() => setShow(false)}>
      {children}
      {show && (
        <div className={`absolute ${positions[position]} px-3 py-1.5 bg-zinc-800 text-zinc-100 text-[10px] font-medium rounded-lg shadow-2xl whitespace-nowrap z-[100] pointer-events-none border border-zinc-700 animate-in fade-in zoom-in-95 duration-200`}>
          {content}
          <div className={`absolute border-4 border-transparent ${arrows[position]}`}></div>
        </div>
      )}
    </div>
  );
};

export default function App() {
  const [images, setImages] = useState<string[]>([]);
  const [description, setDescription] = useState('');
  const [shots, setShots] = useState<StoryboardShot[]>(
    DEFAULT_SHOTS.map((type, idx) => ({ id: idx, type, description: '' }))
  );
  const [generatedPrompt, setGeneratedPrompt] = useState<GeneratedPrompt | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [language, setLanguage] = useState<'english' | 'chinese'>('english');
  const [copied, setCopied] = useState(false);
  const [isCameraOpen, setIsCameraOpen] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    Array.from(files).forEach((file: File) => {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImages(prev => [...prev, reader.result as string].slice(0, 5));
      };
      reader.readAsDataURL(file);
    });
    e.target.value = '';
  };

  const removeImage = (index: number) => {
    setImages(prev => prev.filter((_, i) => i !== index));
  };

  const clearAll = () => {
    if (confirm('Clear everything?')) {
      setImages([]);
      setDescription('');
      setGeneratedPrompt(null);
      setShots(DEFAULT_SHOTS.map((type, idx) => ({ id: idx, type, description: '' })));
    }
  };

  const startCamera = async () => {
    setIsCameraOpen(true);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'user' },
        audio: false 
      });
      streamRef.current = stream;
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
    } catch (err) {
      console.error("Camera access denied", err);
      setIsCameraOpen(false);
      alert("Could not access camera. Please check permissions.");
    }
  };

  const stopCamera = () => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    setIsCameraOpen(false);
  };

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        const dataUrl = canvas.toDataURL('image/jpeg');
        setImages(prev => [...prev, dataUrl].slice(0, 5));
        stopCamera();
      }
    }
  };

  const analyzeImages = async () => {
    if (images.length === 0) return;
    setIsAnalyzing(true);
    try {
      const desc = await gemini.analyzeImages(images);
      setDescription(desc);
    } catch (error) {
      console.error("Analysis failed", error);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const generatePrompt = async () => {
    if (!description) return;
    setIsGenerating(true);
    try {
      const promptData = await gemini.generateStoryboardPrompt(
        description,
        shots
      );
      setGeneratedPrompt(promptData);
    } catch (error) {
      console.error("Generation failed", error);
    } finally {
      setIsGenerating(false);
    }
  };

  const updateShot = (index: number, updates: Partial<StoryboardShot>) => {
    const newShots = [...shots];
    newShots[index] = { ...newShots[index], ...updates };
    setShots(newShots);
  };

  const copyToClipboard = () => {
    if (!generatedPrompt) return;
    const text = language === 'english' ? generatedPrompt.english : generatedPrompt.chinese;
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="flex flex-col md:flex-row h-screen overflow-hidden bg-zinc-950">
      {/* Sidebar: Controls */}
      <aside className="w-full md:w-[420px] bg-zinc-950 border-r border-zinc-800/50 flex flex-col overflow-y-auto p-6 gap-8 custom-scrollbar">
        <header className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-blue-600 p-2 rounded-xl shadow-lg shadow-blue-600/20">
              <Sparkles className="text-white" size={20} />
            </div>
            <div>
              <h1 className="text-lg font-bold text-white leading-tight">
                Storyboard Grid
              </h1>
              <p className="text-[10px] text-zinc-500 uppercase tracking-widest font-semibold">Pro Generator</p>
            </div>
          </div>
          <Tooltip content="Reset everything and start over" position="left">
            <button 
              onClick={clearAll}
              className="p-2 text-zinc-600 hover:text-red-400 hover:bg-red-400/10 rounded-lg transition-all"
              title="Clear All"
            >
              <Trash2 size={18} />
            </button>
          </Tooltip>
        </header>

        {/* Step 1: Reference Images */}
        <section className="space-y-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
              <h2 className="text-xs font-bold text-zinc-500 uppercase tracking-wider flex items-center gap-2">
                <span className="w-5 h-5 bg-zinc-800 rounded flex items-center justify-center text-[10px] text-zinc-400">1</span>
                Reference Images
              </h2>
              <Tooltip content="Upload up to 5 images to ensure character and style consistency.">
                <HelpCircle size={14} className="text-zinc-700 hover:text-zinc-500 cursor-help transition-colors" />
              </Tooltip>
            </div>
            <div className="flex gap-2">
              <Tooltip content="Take a photo with your webcam">
                <button 
                  onClick={startCamera}
                  className="text-xs text-zinc-400 hover:text-white transition-colors flex items-center gap-1 bg-zinc-900 px-2 py-1 rounded-md border border-zinc-800"
                >
                  <Camera size={12} /> Camera
                </button>
              </Tooltip>
              <span className="text-[10px] text-zinc-600 bg-zinc-900 px-2 py-1 rounded-md border border-zinc-800">
                {images.length}/5
              </span>
            </div>
          </div>

          <div className="grid grid-cols-3 gap-2">
            {images.map((img, idx) => (
              <div key={idx} className="relative aspect-square group rounded-xl overflow-hidden border border-zinc-800 bg-zinc-900 transition-transform active:scale-95">
                <img src={img} className="w-full h-full object-cover" alt={`Ref ${idx}`} />
                <button 
                  onClick={() => removeImage(idx)}
                  className="absolute top-1 right-1 p-1 bg-black/60 backdrop-blur-sm rounded-lg opacity-0 group-hover:opacity-100 transition-opacity hover:bg-red-500 text-white"
                >
                  <X size={12} />
                </button>
              </div>
            ))}
            {images.length < 5 && (
              <Tooltip content="Choose files from your device">
                <button 
                  onClick={() => fileInputRef.current?.click()}
                  className="aspect-square w-full rounded-xl border-2 border-dashed border-zinc-800 flex flex-col items-center justify-center gap-1 text-zinc-600 hover:border-zinc-700 hover:text-zinc-400 hover:bg-zinc-900/50 transition-all group"
                >
                  <Plus size={24} className="group-hover:scale-110 transition-transform" />
                  <span className="text-[10px] font-medium">Add Ref</span>
                </button>
              </Tooltip>
            )}
          </div>
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleImageUpload} 
            multiple 
            accept="image/*" 
            className="hidden" 
          />

          <Tooltip content="Analyze uploaded images using AI to generate a detailed description." position="top">
            <button
              onClick={analyzeImages}
              disabled={images.length === 0 || isAnalyzing}
              className={`w-full py-3 px-4 rounded-xl flex items-center justify-center gap-2 font-semibold text-sm transition-all ${
                images.length === 0 || isAnalyzing
                  ? 'bg-zinc-900 text-zinc-700 cursor-not-allowed border border-zinc-800'
                  : 'bg-zinc-100 text-zinc-950 hover:bg-white active:scale-[0.98] shadow-lg shadow-white/5'
              }`}
            >
              {isAnalyzing ? (
                <RefreshCw className="animate-spin" size={18} />
              ) : (
                <Zap size={18} />
              )}
              {isAnalyzing ? 'Analyzing Reference...' : 'Reverse Scene Prompt'}
            </button>
          </Tooltip>
        </section>

        {/* Step 2: Context */}
        <section className="space-y-4">
          <div className="flex items-center gap-2">
            <h2 className="text-xs font-bold text-zinc-500 uppercase tracking-wider flex items-center gap-2">
              <span className="w-5 h-5 bg-zinc-800 rounded flex items-center justify-center text-[10px] text-zinc-400">2</span>
              Scene Context
            </h2>
            <Tooltip content="Refine the character description, clothing, and environment details here.">
              <HelpCircle size={14} className="text-zinc-700 hover:text-zinc-500 cursor-help transition-colors" />
            </Tooltip>
          </div>
          <div className="relative">
            <textarea
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              placeholder="Detailed description of character, clothing, lighting, and environment..."
              className="w-full h-36 bg-zinc-900 border border-zinc-800 rounded-xl p-4 text-sm text-zinc-300 resize-none focus:ring-2 focus:ring-blue-600/50 focus:border-blue-500 outline-none transition-all placeholder:text-zinc-700 leading-relaxed"
            />
            {!description && (
              <div className="absolute inset-0 flex items-center justify-center pointer-events-none opacity-20">
                <ImageIcon size={48} className="text-zinc-400" />
              </div>
            )}
          </div>
        </section>

        {/* Step 3: Shots */}
        <section className="space-y-4">
          <div className="flex items-center gap-2">
            <h2 className="text-xs font-bold text-zinc-500 uppercase tracking-wider flex items-center gap-2">
              <span className="w-5 h-5 bg-zinc-800 rounded flex items-center justify-center text-[10px] text-zinc-400">3</span>
              Grid Shots (3x3)
            </h2>
            <Tooltip content="Select the camera angle and specify details/actions for each frame.">
              <HelpCircle size={14} className="text-zinc-700 hover:text-zinc-500 cursor-help transition-colors" />
            </Tooltip>
          </div>
          <ShotSelector shots={shots} onChange={updateShot} />

          <div className="pt-2">
            <Tooltip content="Generate the master storyboard prompt for AI image engines like Midjourney." position="top">
              <button
                onClick={generatePrompt}
                disabled={!description || isGenerating}
                className={`w-full py-4 px-4 rounded-2xl flex items-center justify-center gap-3 font-bold text-sm tracking-wider transition-all border ${
                  !description || isGenerating
                    ? 'bg-zinc-900 text-zinc-700 cursor-not-allowed border-zinc-800'
                    : 'bg-blue-600 text-white border-blue-500 hover:bg-blue-500 shadow-xl shadow-blue-600/20 active:scale-[0.98]'
                }`}
              >
                {isGenerating ? (
                  <RefreshCw className="animate-spin" size={20} />
                ) : (
                  <Sparkles size={20} />
                )}
                {isGenerating ? 'GENERATING...' : 'GENERATE 3X3 PROMPT'}
              </button>
            </Tooltip>
          </div>
        </section>

        <footer className="mt-auto pt-6 text-[10px] text-zinc-700 flex items-center gap-2 border-t border-zinc-900">
          <Info size={12} />
          <span>Optimized for Flux, Midjourney, and Stable Diffusion.</span>
        </footer>
      </aside>

      {/* Main Area: Result */}
      <main className="flex-1 bg-zinc-900/30 flex flex-col p-6 md:p-12 overflow-y-auto relative">
        <div className="max-w-4xl mx-auto w-full flex flex-col h-full">
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 border-b border-zinc-800/50 pb-8 mb-8">
            <div>
              <h2 className="text-3xl font-black text-white tracking-tight">Master Prompt</h2>
              <div className="flex items-center gap-2 mt-2">
                <span className="px-2 py-0.5 bg-blue-600/10 text-blue-500 border border-blue-500/20 rounded text-[10px] font-bold uppercase tracking-wider">High Consistency</span>
                <span className="px-2 py-0.5 bg-zinc-800 text-zinc-400 rounded text-[10px] font-bold uppercase tracking-wider">3x3 Cinematic Grid</span>
              </div>
            </div>

            <div className="flex items-center gap-1.5 bg-zinc-950 p-1.5 rounded-xl border border-zinc-800 shadow-inner">
              <Tooltip content="Switch prompt language to English" position="bottom">
                <button 
                  onClick={() => setLanguage('english')}
                  className={`px-4 py-2 rounded-lg text-xs font-bold transition-all ${language === 'english' ? 'bg-zinc-800 text-white shadow-lg' : 'text-zinc-500 hover:text-zinc-300'}`}
                >
                  ENGLISH
                </button>
              </Tooltip>
              <Tooltip content="切换提示词语言为中文" position="bottom">
                <button 
                  onClick={() => setLanguage('chinese')}
                  className={`px-4 py-2 rounded-lg text-xs font-bold transition-all ${language === 'chinese' ? 'bg-zinc-800 text-white shadow-lg' : 'text-zinc-500 hover:text-zinc-300'}`}
                >
                  CHINESE
                </button>
              </Tooltip>
            </div>
          </div>

          <div className="flex-1">
            {!generatedPrompt && !isGenerating ? (
              <div className="h-full min-h-[400px] border-2 border-dashed border-zinc-800/50 rounded-[40px] flex flex-col items-center justify-center text-zinc-600 gap-6 group transition-all hover:border-zinc-700/50">
                <div className="p-6 bg-zinc-950 rounded-[32px] border border-zinc-800 shadow-2xl group-hover:scale-110 transition-transform">
                  <Sparkles size={48} className="text-zinc-800" />
                </div>
                <div className="text-center space-y-2">
                  <p className="text-xl font-bold text-zinc-400">Ready for Synthesis</p>
                  <p className="text-sm max-w-sm text-zinc-600 leading-relaxed">
                    Upload your character or scene references. Our AI will craft a perfectly aligned 9-shot cinematic grid prompt.
                  </p>
                </div>
                <div className="flex items-center gap-4 text-xs font-medium text-zinc-700">
                  <span className="flex items-center gap-1.5"><ChevronRight size={14} /> Upload</span>
                  <span className="flex items-center gap-1.5"><ChevronRight size={14} /> Analyze</span>
                  <span className="flex items-center gap-1.5"><ChevronRight size={14} /> Generate</span>
                </div>
              </div>
            ) : isGenerating ? (
              <div className="h-full min-h-[400px] flex flex-col items-center justify-center gap-8">
                <div className="relative">
                  <div className="w-24 h-24 border-4 border-zinc-800 rounded-full"></div>
                  <div className="absolute inset-0 w-24 h-24 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                  <div className="absolute inset-0 flex items-center justify-center">
                    <Sparkles size={32} className="text-blue-500 animate-pulse" />
                  </div>
                </div>
                <div className="text-center space-y-3">
                  <p className="text-2xl font-black text-white tracking-tight">Crafting Storyboard...</p>
                  <p className="text-zinc-500 text-sm font-medium">Syncing shot logic with reference consistency tokens</p>
                </div>
              </div>
