export default function App() {
  const [images, setImages] = useState<string[]>([]);
  const [description, setDescription] = useState('');
  const [shots, setShots] = useState<StoryboardShot[]>(
    DEFAULT_SHOTS.map((type, idx) => ({ id: idx, type, description: '' }))
  );
  const [refreshingShots, setRefreshingShots] = useState<Record<number, boolean>>({});
  const [generatedPrompt, setGeneratedPrompt] = useState<GeneratedPrompt | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [language, setLanguage] = useState<'english' | 'chinese'>('english');
  const [copied, setCopied] = useState(false);
  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const [facingMode, setFacingMode] = useState<VideoFacingModeEnum>('user');

  const fileInputRef = useRef<HTMLInputElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const t = TRANSLATIONS[language];

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    Array.from(files).forEach((file: File) => {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImages(prev => [...prev, reader.result as string].slice(0, 5));
      };
      reader.readAsDataURL(file);
    });
    e.target.value = '';
  };

  const removeImage = (index: number) => {
    setImages(prev => prev.filter((_, i) => i !== index));
  };

  const clearAll = () => {
    if (confirm(t.clearConfirm)) {
      setImages([]);
      setDescription('');
      setGeneratedPrompt(null);
      setShots(DEFAULT_SHOTS.map((type, idx) => ({ id: idx, type, description: '' })));
    }
  };

  const startCamera = async (mode: VideoFacingModeEnum = 'user') => {
    setIsCameraOpen(true);
    setFacingMode(mode);

    // Stop existing stream if switching
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
    }

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: mode },
        audio: false 
      });
      streamRef.current = stream;
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
    } catch (err) {
      console.error("Camera access denied", err);
      setIsCameraOpen(false);
      alert("Could not access camera. Please check permissions.");
    }
  };

  const stopCamera = () => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    setIsCameraOpen(false);
  };

  const toggleCamera = () => {
    const newMode = facingMode === 'user' ? 'environment' : 'user';
    startCamera(newMode);
  };

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        const dataUrl = canvas.toDataURL('image/jpeg');
        setImages(prev => [...prev, dataUrl].slice(0, 5));
        stopCamera();
      }
    }
  };

  const analyzeImages = async () => {
    if (images.length === 0) return;
    setIsAnalyzing(true);
    try {
      const desc = await gemini.analyzeImages(images);
      setDescription(desc);
    } catch (error) {
      console.error("Analysis failed", error);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleRefreshShot = async (index: number) => {
    if (!description) return;
    setRefreshingShots(prev => ({ ...prev, [index]: true }));
    try {
      const suggested = await gemini.suggestShotDescription(description, shots[index].type);
      updateShot(index, { description: suggested });
    } catch (error) {
      console.error("Shot suggestion failed", error);
    } finally {
      setRefreshingShots(prev => ({ ...prev, [index]: false }));
    }
  };

  const generatePrompt = async () => {
    if (!description) return;
    setIsGenerating(true);
    try {
      const promptData = await gemini.generateStoryboardPrompt(
        description,
        shots
      );
      setGeneratedPrompt(promptData);
    } catch (error) {
      console.error("Generation failed", error);
    } finally {
      setIsGenerating(false);
    }
  };

  const updateShot = (index: number, updates: Partial<StoryboardShot>) => {
    const newShots = [...shots];
    newShots[index] = { ...newShots[index], ...updates };
    setShots(newShots);
  };

  const copyToClipboard = () => {
    if (!generatedPrompt) return;
    const text = language === 'english' ? generatedPrompt.english : generatedPrompt.chinese;
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="flex flex-col md:flex-row h-screen overflow-hidden bg-zinc-950">
      {/* Sidebar: Controls */}
      <aside className="w-full md:w-[420px] bg-zinc-950 border-r border-zinc-800/50 flex flex-col overflow-y-auto p-6 gap-8 custom-scrollbar">
        <header className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-blue-600 p-2 rounded-xl shadow-lg shadow-blue-600/20">
              <Sparkles className="text-white" size={20} />
            </div>
            <div>
              <h1 className="text-lg font-bold text-white leading-tight">
                {t.appName}
              </h1>
              <p className="text-[10px] text-zinc-500 uppercase tracking-widest font-semibold">{t.proGen}</p>
            </div>
          </div>
          <Tooltip content={t.reset} position="left">
            <button 
              onClick={clearAll}
              className="p-2 text-zinc-600 hover:text-red-400 hover:bg-red-400/10 rounded-lg transition-all"
              title="Clear All"
            >
              <Trash2 size={18} />
            </button>
          </Tooltip>
        </header>

        {/* Step 1: Reference Images */}
        <section className="space-y-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
              <h2 className="text-xs font-bold text-zinc-500 uppercase tracking-wider flex items-center gap-2">
                <span className="w-5 h-5 bg-zinc-800 rounded flex items-center justify-center text-[10px] text-zinc-400">1</span>
                {t.step1Title}
              </h2>
              <Tooltip content={t.step1Tooltip}>
                <HelpCircle size={14} className="text-zinc-700 hover:text-zinc-500 cursor-help transition-colors" />
              </Tooltip>
            </div>
            <div className="flex gap-2">
              <Tooltip content={t.cameraTooltip}>
                <button 
                  onClick={() => startCamera('user')}
                  className="text-xs text-zinc-400 hover:text-white transition-colors flex items-center gap-1 bg-zinc-900 px-2 py-1 rounded-md border border-zinc-800"
                >
                  <Camera size={12} /> {t.camera}
                </button>
              </Tooltip>
              <span className="text-[10px] text-zinc-600 bg-zinc-900 px-2 py-1 rounded-md border border-zinc-800">
                {images.length}/5
              </span>
            </div>
          </div>

          <div className="grid grid-cols-3 gap-2">
            {images.map((img, idx) => (
              <div key={idx} className="relative aspect-square group rounded-xl overflow-hidden border border-zinc-800 bg-zinc-900 transition-transform active:scale-95">
                <img src={img} className="w-full h-full object-cover" alt={`Ref ${idx}`} />
                <button 
                  onClick={() => removeImage(idx)}
                  className="absolute top-1 right-1 p-1 bg-black/60 backdrop-blur-sm rounded-lg opacity-0 group-hover:opacity-100 transition-opacity hover:bg-red-500 text-white"
                >
                  <X size={12} />
                </button>
              </div>
            ))}
            {images.length < 5 && (
              <Tooltip content={t.addRefTooltip}>
                <button 
                  onClick={() => fileInputRef.current?.click()}
                  className="aspect-square w-full rounded-xl border-2 border-dashed border-zinc-800 flex flex-col items-center justify-center gap-1 text-zinc-600 hover:border-zinc-700 hover:text-zinc-400 hover:bg-zinc-900/50 transition-all group"
                >
                  <Plus size={24} className="group-hover:scale-110 transition-transform" />
                  <span className="text-[10px] font-medium">{t.addRef}</span>
                </button>
              </Tooltip>
            )}
          </div>
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleImageUpload} 
            multiple 
            accept="image/*" 
            className="hidden" 
          />

