export type ShotType = 
  | 'Extreme Close-up' 
  | 'Close-up' 
  | 'Medium Shot' 
  | 'Medium Full Shot' 
  | 'Full Shot' 
  | 'Wide Shot' 
  | 'Extreme Wide Shot' 
  | 'Bird\'s Eye View' 
  | 'Low Angle Shot' 
  | 'High Angle Shot' 
  | 'Over the Shoulder';

export interface StoryboardShot {
  id: number;
  type: ShotType;
  description: string;
}

export interface GeneratedPrompt {
  english: string;
  chinese: string;
  shotDescriptions: string[]; // Expanded descriptions for each of the 9 shots
}

export interface AnalysisResult {
  description: string;
  suggestedShots: StoryboardShot[];
}

import { GoogleGenAI, Type } from "@google/genai";
import { StoryboardShot, GeneratedPrompt } from "../types";

const MODEL_NAME = 'gemini-3-flash-preview';

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  /**
   * Analyzes uploaded images to extract character/scene details.
   */
  async analyzeImages(imageB64s: string[]): Promise<string> {
    const parts = imageB64s.map(data => ({
      inlineData: {
        mimeType: 'image/jpeg',
        data: data.split(',')[1] || data,
      },
    }));

    const response = await this.ai.models.generateContent({
      model: MODEL_NAME,
      contents: {
        parts: [
          ...parts,
          { text: "Analyze these reference images. Provide a very detailed physical description of the main subject (person/object), their clothing, materials, facial features, and the lighting/environment. This description will be used as a base for AI image generation consistency. Focus on 'visual tokens' like specific colors, textures, and styles. Output only the description." }
        ]
      },
    });

    return response.text || "Could not analyze image.";
  }

  /**
   * Suggests a specific action or detail for a single shot slot.
   */
  async suggestShotDescription(baseDescription: string, shotType: string): Promise<string> {
    const response = await this.ai.models.generateContent({
      model: MODEL_NAME,
      contents: `
        Context: ${baseDescription}
        Shot Type: ${shotType}

        TASK: Suggest a short, cinematic, and descriptive action or detail for this specific shot type within the given context. 
        Focus on physical movement, lighting effects, or atmospheric details that fit the shot type.
        Output only the suggested description (max 15 words, English).
      `
    });
    return response.text?.trim() || "";
  }

  /**
   * Generates the structured storyboard prompt in both EN and CN.
   */
  async generateStoryboardPrompt(
    baseDescription: string, 
    shots: StoryboardShot[]
  ): Promise<GeneratedPrompt> {
    const response = await this.ai.models.generateContent({
      model: MODEL_NAME,
      contents: `
        Base Character/Scene Description: ${baseDescription}

        Detailed Shot Requirements for 3x3 Grid:
        ${shots.map((s, i) => `Slot ${i + 1}: [Type: ${s.type}] ${s.description ? `[Custom Detail: ${s.description}]` : ''}`).join('\n')}

        TASK: Create a professional, highly structured AI image generation prompt for a 3x3 grid in both English and Chinese.

        ENHANCEMENT RULES:
        1. Use clear visual headers (e.g., [CORE PARAMETERS], [SHOT SEQUENCE]).
        2. Use "markdown-like" emphasis (**TEXT**) for key terms like character features, shot types, and technical specs.
        3. Use line separators (--- or ===) to organize sections.
        4. For each shot, if a "Custom Detail" is provided, PRIORITIZE it in the description while maintaining the specified Shot Type.
        5. Strictly maintain character consistency throughout all 9 shots.

        English Version Format:
        "[CORE PARAMETERS]
        Style: Cinematic 8K, 16:9 Aspect Ratio.
        Base: [detailed description with **emphasized tokens**]

        --------------------------------------------------
        [3x3 GRID SHOT SEQUENCE]
        --------------------------------------------------
        **Shot 01:** [Shot Type] - [Action/Description prioritizing user details]
        **Shot 02:** ...
        ...
        **Shot 09:** ...

        [TECHNICAL SPECIFICATIONS]
        Grid: 3x3, Resolution: 8K, Consistency Level: Maximum."

        Chinese Version Format:
        "[核心场景参数]
        画幅: 16:9, 分辨率: 8K 高清
        描述: [详细场景内容，使用 **加粗** 强调关键特征]

        --------------------------------------------------
        [3x3 分镜细节序列]
        --------------------------------------------------
        **镜头 01:** [景别] - [描述内容]
        ...
        **镜头 09:** ...

        Return the result in JSON format with 'english', 'chinese', and 'shotDescriptions' keys.
        'shotDescriptions' must be an array of 9 strings, each containing ONLY the expanded description for each corresponding shot in English (e.g., "The character is sitting by the window in soft morning light").
      `,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            english: { type: Type.STRING },
            chinese: { type: Type.STRING },
            shotDescriptions: { 
              type: Type.ARRAY,
              items: { type: Type.STRING }
            }
          },
          required: ["english", "chinese", "shotDescriptions"]
        }
      }
    });

    try {
      const parsed = JSON.parse(response.text || '{}');
      return {
        english: parsed.english,
        chinese: parsed.chinese,
        shotDescriptions: parsed.shotDescriptions || []
      };
    } catch (e) {
      return { 
        english: response.text || "Error generating EN prompt", 
        chinese: "无法生成中文提示词",
        shotDescriptions: []
      };
    }
  }
}

import React from 'react';
