interface ShotSelectorProps {
  shots: StoryboardShot[];
  onChange: (index: number, updates: Partial<StoryboardShot>) => void;
  onRefresh: (index: number) => void;
  refreshingShots: Record<number, boolean>;
  language: 'english' | 'chinese';
  t: any;
}

export const ShotSelector: React.FC<ShotSelectorProps> = ({ 
  shots, 
  onChange, 
  onRefresh, 
  refreshingShots, 
  language,
  t
}) => {
  const ui = {
    slot: language === 'english' ? 'Slot' : '镜头',
    placeholder: language === 'english' ? 'Action/Details...' : '动作/细节描述...',
  };

  return (
    <div className="grid grid-cols-3 gap-3">
      {shots.map((shot, idx) => (
        <div key={idx} className="flex flex-col gap-1.5 p-2 bg-zinc-900/50 border border-zinc-800/50 rounded-xl hover:border-zinc-800 transition-colors">
          <div className="flex items-center justify-between px-1">
            <label className="text-[9px] font-black uppercase text-zinc-600 tracking-wider">
              {ui.slot} {String(idx + 1).padStart(2, '0')}
            </label>
          </div>

          <select
            value={shot.type}
            onChange={(e) => onChange(idx, { type: e.target.value as ShotType })}
            className="w-full bg-zinc-950 border border-zinc-800 text-zinc-300 text-[10px] font-medium rounded-lg px-2 py-1.5 focus:ring-1 focus:ring-blue-500/50 focus:border-blue-500 outline-none transition-all cursor-pointer"
          >
            {SHOT_TYPES.map((type) => (
              <option key={type} value={type}>
                {language === 'english' ? SHOT_TYPES_MAP[type].en : SHOT_TYPES_MAP[type].cn}
              </option>
            ))}
          </select>

          <div className="relative">
            <input
              type="text"
              value={shot.description}
              onChange={(e) => onChange(idx, { description: e.target.value })}
              placeholder={ui.placeholder}
              className="w-full bg-zinc-950 border border-zinc-800 text-zinc-400 text-[10px] rounded-lg pl-2 pr-8 py-1.5 focus:ring-1 focus:ring-blue-500/50 focus:border-blue-500 outline-none transition-all placeholder:text-zinc-700"
            />
            <button
              onClick={() => onRefresh(idx)}
              disabled={refreshingShots[idx]}
              className={`absolute right-1 top-1/2 -translate-y-1/2 p-1 text-zinc-600 hover:text-blue-400 transition-colors rounded-md ${refreshingShots[idx] ? 'animate-spin' : ''}`}
              title={t.refreshShot}
            >
              <RefreshCw size={12} />
            </button>
          </div>
        </div>
      ))}
    </div>
  );
};

