export type ShotType = 
  | 'Extreme Close-up' 
  | 'Close-up' 
  | 'Medium Shot' 
  | 'Medium Full Shot' 
  | 'Full Shot' 
  | 'Wide Shot' 
  | 'Extreme Wide Shot' 
  | 'Bird\'s Eye View' 
  | 'Low Angle Shot' 
  | 'High Angle Shot' 
  | 'Over the Shoulder';

export interface StoryboardShot {
  id: number;
  type: ShotType;
  en: string;
  cn: string;
}

export interface GeneratedPrompt {
  english: string;
  chinese: string;
  shotDescriptionsEn: string[];
  shotDescriptionsCn: string[];
}

export interface AnalysisResult {
  description: string;
  suggestedShots: StoryboardShot[];
}

import { GoogleGenAI, Type } from "@google/genai";
import { StoryboardShot, GeneratedPrompt } from "../types";

const MODEL_NAME = 'gemini-3-flash-preview';

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  async analyzeImages(imageB64s: string[]): Promise<{ english: string; chinese: string }> {
    const parts = imageB64s.map(data => ({
      inlineData: {
        mimeType: 'image/jpeg',
        data: data.split(',')[1] || data,
      },
    }));

    const response = await this.ai.models.generateContent({
      model: MODEL_NAME,
      contents: {
        parts: [
          ...parts,
          { text: "Analyze these reference images. Provide a very detailed physical description of the main subject (person/object), their clothing, materials, facial features, and the lighting/environment. Output the description in both English and Chinese as a JSON object with keys 'english' and 'chinese'." }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            english: { type: Type.STRING },
            chinese: { type: Type.STRING }
          },
          required: ["english", "chinese"]
        }
      }
    });

    try {
      return JSON.parse(response.text || '{"english": "", "chinese": ""}');
    } catch (e) {
      return { 
        english: response.text || "Could not analyze image.",
        chinese: "无法分析图片"
      };
    }
  }

  async suggestShotDescription(baseDescription: string, shotType: string): Promise<{ en: string; cn: string }> {
    const response = await this.ai.models.generateContent({
      model: MODEL_NAME,
      contents: `
        Context: ${baseDescription}
        Shot Type: ${shotType}
        TASK: Suggest a short, cinematic, and descriptive action or detail for this specific shot type.
        Return as JSON with keys 'en' and 'cn'. Max 15 words each.
      `,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            en: { type: Type.STRING },
            cn: { type: Type.STRING }
          },
          required: ["en", "cn"]
        }
      }
    });
    try {
      return JSON.parse(response.text || '{"en": "", "cn": ""}');
    } catch {
      return { en: "", cn: "" };
    }
  }

  async generateStoryboardPrompt(
    baseDescription: string, 
    shots: StoryboardShot[]
  ): Promise<GeneratedPrompt> {
    const response = await this.ai.models.generateContent({
      model: MODEL_NAME,
      contents: `
        Base Description: ${baseDescription}
        Shots:
        ${shots.map((s, i) => `Slot ${i + 1}: [${s.type}] EN: ${s.en} | CN: ${s.cn}`).join('\n')}

        TASK: Create a professional 3x3 grid prompt in EN and CN.
        Also provide individual expanded descriptions for all 9 shots in both EN and CN.
        Return JSON with:
        'english': the full master prompt in English
        'chinese': the full master prompt in Chinese
        'shotDescriptionsEn': array of 9 expanded EN strings
        'shotDescriptionsCn': array of 9 expanded CN strings
      `,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            english: { type: Type.STRING },
            chinese: { type: Type.STRING },
            shotDescriptionsEn: { type: Type.ARRAY, items: { type: Type.STRING } },
            shotDescriptionsCn: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["english", "chinese", "shotDescriptionsEn", "shotDescriptionsCn"]
        }
      }
    });

    try {
      return JSON.parse(response.text || '{}');
    } catch (e) {
      return { english: "", chinese: "", shotDescriptionsEn: [], shotDescriptionsCn: [] };
    }
  }
}

