export default function App() {
  const [images, setImages] = useState<string[]>([]);
  const [context, setContext] = useState({ english: '', chinese: '' });
  const [contextEditLang, setContextEditLang] = useState<'english' | 'chinese'>('english');
  const [shots, setShots] = useState<StoryboardShot[]>(
    DEFAULT_SHOTS.map((type, idx) => ({ id: idx, type, en: '', cn: '' }))
  );
  const [shotEditLang, setShotEditLang] = useState<'en' | 'cn'>('en');
  const [refreshingShots, setRefreshingShots] = useState<Record<number, boolean>>({});
  const [generatedPrompt, setGeneratedPrompt] = useState<GeneratedPrompt | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [language, setLanguage] = useState<'english' | 'chinese'>('english');
  const [copied, setCopied] = useState(false);
  const [synced, setSynced] = useState(false);
  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const [facingMode, setFacingMode] = useState<VideoFacingModeEnum>('user');

  const fileInputRef = useRef<HTMLInputElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const t = TRANSLATIONS[language];

  useEffect(() => {
    setContextEditLang(language);
    setShotEditLang(language === 'english' ? 'en' : 'cn');
  }, [language]);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;
    Array.from(files).forEach((file: File) => {
      const reader = new FileReader();
      reader.onloadend = () => setImages(prev => [...prev, reader.result as string].slice(0, 5));
      reader.readAsDataURL(file);
    });
    e.target.value = '';
  };

  const removeImage = (index: number) => setImages(prev => prev.filter((_, i) => i !== index));

  const clearAll = () => {
    if (confirm(t.clearConfirm)) {
      setImages([]);
      setContext({ english: '', chinese: '' });
      setGeneratedPrompt(null);
      setShots(DEFAULT_SHOTS.map((type, idx) => ({ id: idx, type, en: '', cn: '' })));
    }
  };

  const startCamera = async (mode: VideoFacingModeEnum = 'user') => {
    setIsCameraOpen(true);
    setFacingMode(mode);
    if (streamRef.current) streamRef.current.getTracks().forEach(track => track.stop());
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: mode } });
      streamRef.current = stream;
      if (videoRef.current) videoRef.current.srcObject = stream;
    } catch (err) {
      setIsCameraOpen(false);
      alert("Camera access denied.");
    }
  };

  const stopCamera = () => {
    if (streamRef.current) streamRef.current.getTracks().forEach(track => track.stop());
    setIsCameraOpen(false);
  };

  const analyzeImages = async () => {
    if (images.length === 0) return;
    setIsAnalyzing(true);
    try {
      const res = await gemini.analyzeImages(images);
      setContext(res);
    } finally { setIsAnalyzing(false); }
  };

  const handleRefreshShot = async (index: number) => {
    const base = context.english || context.chinese;
    if (!base) return;
    setRefreshingShots(prev => ({ ...prev, [index]: true }));
    try {
      const res = await gemini.suggestShotDescription(base, shots[index].type);
      updateShot(index, { en: res.en, cn: res.cn });
    } finally { setRefreshingShots(prev => ({ ...prev, [index]: false })); }
  };

  const syncToInputs = () => {
    if (!generatedPrompt) return;
    setShots(shots.map((s, i) => ({
      ...s,
      en: generatedPrompt.shotDescriptionsEn[i] || s.en,
      cn: generatedPrompt.shotDescriptionsCn[i] || s.cn
    })));
    setSynced(true);
    setTimeout(() => setSynced(false), 2000);
  };

  const generatePrompt = async () => {
    const base = context.english || context.chinese;
    if (!base) return;
    setIsGenerating(true);
    try {
      const res = await gemini.generateStoryboardPrompt(base, shots);
      setGeneratedPrompt(res);
    } finally { setIsGenerating(false); }
  };

  const updateShot = (index: number, updates: Partial<StoryboardShot>) => {
    const newShots = [...shots];
    newShots[index] = { ...newShots[index], ...updates };
    setShots(newShots);
  };

  return (
    <div className="flex flex-col md:flex-row h-screen overflow-hidden bg-zinc-950 text-zinc-100">
      <aside className="w-full md:w-[420px] bg-zinc-950 border-r border-zinc-800/50 flex flex-col overflow-y-auto p-6 gap-8 custom-scrollbar">
        <header className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-blue-600 p-2 rounded-xl shadow-lg shadow-blue-600/20"><Sparkles size={20} /></div>
            <div>
              <h1 className="text-lg font-bold leading-tight">{t.appName}</h1>
              <p className="text-[10px] text-zinc-500 uppercase tracking-widest font-semibold">{t.proGen}</p>
            </div>
          </div>
          <button onClick={clearAll} className="p-2 text-zinc-600 hover:text-red-400 rounded-lg transition-all"><Trash2 size={18} /></button>
        </header>

        <section className="space-y-4">
          <div className="flex justify-between items-center">
            <h2 className="text-xs font-bold text-zinc-500 uppercase tracking-wider flex items-center gap-2">
              <span className="w-5 h-5 bg-zinc-800 rounded flex items-center justify-center text-[10px]">1</span> {t.step1Title}
            </h2>
            <div className="flex gap-2">
              <button onClick={() => startCamera('user')} className="text-[10px] text-zinc-400 hover:text-white bg-zinc-900 px-2 py-1 rounded border border-zinc-800 flex items-center gap-1"><Camera size={12} /> {t.camera}</button>
              <span className="text-[10px] text-zinc-600 bg-zinc-900 px-2 py-1 rounded border border-zinc-800">{images.length}/5</span>
            </div>
          </div>
          <div className="grid grid-cols-3 gap-2">
            {images.map((img, idx) => (
              <div key={idx} className="relative aspect-square group rounded-xl overflow-hidden border border-zinc-800 bg-zinc-900">
                <img src={img} className="w-full h-full object-cover" />
                <button onClick={() => removeImage(idx)} className="absolute top-1 right-1 p-1 bg-black/60 rounded-lg opacity-0 group-hover:opacity-100 transition-opacity hover:bg-red-500"><X size={12} /></button>
              </div>
            ))}
            {images.length < 5 && (
              <button onClick={() => fileInputRef.current?.click()} className="aspect-square border-2 border-dashed border-zinc-800 rounded-xl flex flex-col items-center justify-center text-zinc-600 hover:bg-zinc-900/50 transition-all"><Plus size={24} /></button>
            )}
          </div>
          <input type="file" ref={fileInputRef} onChange={handleImageUpload} multiple accept="image/*" className="hidden" />
          <button onClick={analyzeImages} disabled={images.length === 0 || isAnalyzing} className="w-full py-3 rounded-xl flex items-center justify-center gap-2 font-semibold text-sm transition-all bg-zinc-100 text-zinc-950 hover:bg-white disabled:bg-zinc-900 disabled:text-zinc-700">
            {isAnalyzing ? <RefreshCw className="animate-spin" size={18} /> : <Zap size={18} />} {isAnalyzing ? t.analyzeBtnLoading : t.analyzeBtn}
          </button>
        </section>

        <section className="space-y-4">
          <div className="flex justify-between items-center">
            <h2 className="text-xs font-bold text-zinc-500 uppercase tracking-wider flex items-center gap-2">
              <span className="w-5 h-5 bg-zinc-800 rounded flex items-center justify-center text-[10px]">2</span> {t.step2Title}
            </h2>
            <div className="flex bg-zinc-900 p-1 rounded-lg border border-zinc-800">
              <button onClick={() => setContextEditLang('english')} className={`px-2 py-1 rounded text-[9px] font-bold ${contextEditLang === 'english' ? 'bg-zinc-700 text-white' : 'text-zinc-500'}`}>{t.contextLangEn}</button>
              <button onClick={() => setContextEditLang('chinese')} className={`px-2 py-1 rounded text-[9px] font-bold ${contextEditLang === 'chinese' ? 'bg-zinc-700 text-white' : 'text-zinc-500'}`}>{t.contextLangCn}</button>
            </div>
          </div>
          <textarea value={context[contextEditLang]} onChange={e => setContext(prev => ({...prev, [contextEditLang]: e.target.value}))} placeholder={t.textareaPlaceholder} className="w-full h-32 bg-zinc-900 border border-zinc-800 rounded-xl p-4 text-sm text-zinc-300 resize-none focus:border-blue-500 outline-none transition-all leading-relaxed" />
        </section>

        <section className="space-y-4">
          <div className="flex justify-between items-center">
            <h2 className="text-xs font-bold text-zinc-500 uppercase tracking-wider flex items-center gap-2">
              <span className="w-5 h-5 bg-zinc-800 rounded flex items-center justify-center text-[10px]">3</span> {t.step3Title}
            </h2>
            <div className="flex bg-zinc-900 p-1 rounded-lg border border-zinc-800">
              <button onClick={() => setShotEditLang('en')} className={`px-2 py-1 rounded text-[9px] font-bold ${shotEditLang === 'en' ? 'bg-zinc-700 text-white' : 'text-zinc-500'}`}>EN</button>
              <button onClick={() => setShotEditLang('cn')} className={`px-2 py-1 rounded text-[9px] font-bold ${shotEditLang === 'cn' ? 'bg-zinc-700 text-white' : 'text-zinc-500'}`}>CN</button>
            </div>
          </div>
          <ShotSelector shots={shots} onChange={updateShot} onRefresh={handleRefreshShot} refreshingShots={refreshingShots} language={language} shotEditLang={shotEditLang} t={t} />
          <button onClick={generatePrompt} disabled={(!context.english && !context.chinese) || isGenerating} className="w-full py-4 rounded-2xl flex items-center justify-center gap-3 font-bold text-sm tracking-wider transition-all bg-blue-600 hover:bg-blue-500 disabled:bg-zinc-900 disabled:text-zinc-700 shadow-xl shadow-blue-600/20 active:scale-95">
            {isGenerating ? <RefreshCw className="animate-spin" size={20} /> : <Sparkles size={20} />} {isGenerating ? t.generateBtnLoading : t.generateBtn}
          </button>
        </section>
      </aside>

      <main className="flex-1 flex flex-col p-12 overflow-y-auto bg-zinc-900/30">
        <div className="max-w-4xl mx-auto w-full flex flex-col h-full">
          <div className="flex justify-between items-center border-b border-zinc-800/50 pb-8 mb-8">
            <div>
              <h2 className="text-3xl font-black tracking-tight">{t.masterPrompt}</h2>
              <div className="flex gap-2 mt-2">
                <span className="px-2 py-0.5 bg-blue-600/10 text-blue-500 border border-blue-500/20 rounded text-[10px] font-bold uppercase">{t.consistencyBadge}</span>
                <span className="px-2 py-0.5 bg-zinc-800 text-zinc-400 rounded text-[10px] font-bold uppercase">{t.gridBadge}</span>
              </div>
            </div>
            <div className="flex bg-zinc-950 p-1.5 rounded-xl border border-zinc-800 shadow-inner">
              <button onClick={() => setLanguage('english')} className={`px-4 py-2 rounded-lg text-xs font-bold transition-all ${language === 'english' ? 'bg-zinc-800 text-white shadow-lg' : 'text-zinc-500 hover:text-zinc-300'}`}>ENGLISH</button>
              <button onClick={() => setLanguage('chinese')} className={`px-4 py-2 rounded-lg text-xs font-bold transition-all ${language === 'chinese' ? 'bg-zinc-800 text-white shadow-lg' : 'text-zinc-500 hover:text-zinc-300'}`}>中文</button>
            </div>
          </div>

          <div className="flex-1">
            {!generatedPrompt && !isGenerating ? (
              <div className="h-full border-2 border-dashed border-zinc-800/50 rounded-[40px] flex flex-col items-center justify-center text-zinc-600 gap-6">
                <div className="p-6 bg-zinc-950 rounded-[32px] border border-zinc-800 shadow-2xl"><Sparkles size={48} className="text-zinc-800" /></div>
                <div className="text-center space-y-2">
                  <p className="text-xl font-bold text-zinc-400">{t.readyTitle}</p>
                  <p className="text-sm max-w-sm text-zinc-600">{t.readyDesc}</p>
                </div>
              </div>
            ) : isGenerating ? (
              <div className="h-full flex flex-col items-center justify-center gap-8">
                <div className="relative">
                  <div className="w-24 h-24 border-4 border-zinc-800 rounded-full"></div>
                  <div className="absolute inset-0 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                  <div className="absolute inset-0 flex items-center justify-center"><Sparkles size={32} className="text-blue-500 animate-pulse" /></div>
                </div>
                <p className="text-2xl font-black tracking-tight">{t.craftingTitle}</p>
              </div>
            ) : (
              <div className="relative group animate-in fade-in slide-in-from-bottom-4 duration-500">
                <div className="absolute -inset-1 bg-gradient-to-br from-blue-600/30 to-purple-600/30 rounded-[32px] blur-xl opacity-50 group-hover:opacity-100 transition-opacity"></div>
                <div className="relative bg-zinc-950 border border-zinc-800 rounded-[32px] overflow-hidden shadow-2xl">
                  <div className="flex items-center justify-between px-8 py-5 border-b border-zinc-800 bg-zinc-950/50">
                    <span className="text-[10px] text-zinc-500 font-mono tracking-widest uppercase font-black">Cohesive_Grid_Output.txt</span>
                    <div className="flex gap-3">
                      <button onClick={syncToInputs} className="flex items-center gap-2 px-5 py-2 bg-zinc-800 text-zinc-100 rounded-xl text-xs font-black hover:bg-zinc-700 transition-all active:scale-95 shadow-lg border border-zinc-700">
                        {synced ? <Check size={16} /> : <ArrowLeftRight size={16} />} {synced ? t.syncedMsg : t.syncBtn}
                      </button>
                      <button onClick={copyToClipboard} className="flex items-center gap-2 px-5 py-2 bg-white text-zinc-950 rounded-xl text-xs font-black hover:bg-zinc-100 transition-all active:scale-95 shadow-lg shadow-white/5">
                        {copied ? <Check size={16} /> : <Copy size={16} />} {copied ? t.copiedBtn : t.copyBtn}
                      </button>
                    </div>
                  </div>
                  <div className="p-8 max-h-[60vh] overflow-y-auto custom-scrollbar">
                    <pre className="whitespace-pre-wrap text-zinc-300 font-mono text-xs md:text-sm leading-relaxed tracking-tight">
                      {language === 'english' ? generatedPrompt?.english : generatedPrompt?.chinese}
                    </pre>
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>
      </main>

      {isCameraOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-zinc-950/90 backdrop-blur-sm p-4">
          <div className="bg-zinc-900 rounded-[32px] border border-zinc-800 overflow-hidden max-w-lg w-full animate-in zoom-in-95 duration-300">
            <div className="p-6 border-b border-zinc-800 flex items-center justify-between">
              <h3 className="text-lg font-bold flex items-center gap-2"><Camera className="text-blue-500" /> {t.cameraModalTitle}</h3>
              <button onClick={stopCamera} className="p-2 text-zinc-500 hover:text-white transition-colors"><X size={20} /></button>
            </div>
            <div className="relative aspect-[4/3] bg-black">
              <video ref={videoRef} autoPlay playsInline className={`w-full h-full object-cover ${facingMode === 'user' ? 'mirror' : ''}`} />
            </div>
            <div className="p-8 flex justify-center">
              <button onClick={capturePhoto} className="group relative w-20 h-20 rounded-full bg-zinc-800 p-1 border-4 border-zinc-700 hover:border-blue-500 active:scale-90">
                <div className="w-full h-full rounded-full bg-white group-hover:bg-blue-500"></div>
              </button>
            </div>
          </div>
        </div>
      )}
      <canvas ref={canvasRef} className="hidden" />
    </div>
  );
}

import React from 'react';
import { ShotType, StoryboardShot } from '../types';
import { SHOT_TYPES, SHOT_TYPES_MAP } from '../constants';
import { RefreshCw } from 'lucide-react';

interface ShotSelectorProps {
  shots: StoryboardShot[];
  onChange: (index: number, updates: Partial<StoryboardShot>) => void;
  onRefresh: (index: number) => void;
  refreshingShots: Record<number, boolean>;
  language: 'english' | 'chinese';
  shotEditLang: 'en' | 'cn';
  t: any;
}

export const ShotSelector: React.FC<ShotSelectorProps> = ({ 
  shots, 
  onChange, 
  onRefresh, 
  refreshingShots, 
  language,
  shotEditLang,
  t
}) => {
  const ui = {
    slot: language === 'english' ? 'Slot' : '镜头',
    placeholder: language === 'english' ? 'Describe action or visual details...' : '描述动作或视觉细节...',
  };

  return (
    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
      {shots.map((shot, idx) => (
        <div key={idx} className="flex flex-col gap-2 p-3 bg-zinc-900/50 border border-zinc-800/60 rounded-xl hover:border-zinc-700 transition-all shadow-sm">
          <div className="flex items-center justify-between">
            <label className="text-[10px] font-black uppercase text-zinc-500 tracking-wider flex items-center gap-1.5">
              <span className="w-1.5 h-1.5 rounded-full bg-blue-500"></span>
              {ui.slot} {String(idx + 1).padStart(2, '0')}
            </label>
            <span className="text-[9px] font-bold text-zinc-600 bg-zinc-950 px-1.5 py-0.5 rounded border border-zinc-800 uppercase">
              {shotEditLang}
            </span>
          </div>

          <select
            value={shot.type}
            onChange={(e) => onChange(idx, { type: e.target.value as ShotType })}
            className="w-full bg-zinc-950 border border-zinc-800 text-zinc-300 text-[11px] font-semibold rounded-lg px-2 py-2 focus:ring-1 focus:ring-blue-500/50 focus:border-blue-500 outline-none transition-all cursor-pointer hover:bg-zinc-900"
          >
            {SHOT_TYPES.map((type) => (
              <option key={type} value={type}>
                {language === 'english' ? SHOT_TYPES_MAP[type].en : SHOT_TYPES_MAP[type].cn}
              </option>
            ))}
          </select>

          <div className="relative group/shot flex-1">
            <textarea
              value={shot[shotEditLang]}
              onChange={(e) => onChange(idx, { [shotEditLang]: e.target.value })}
              placeholder={ui.placeholder}
              rows={4}
              className="w-full h-full bg-zinc-950 border border-zinc-800 text-zinc-400 text-[11px] rounded-lg pl-3 pr-9 py-2.5 focus:ring-1 focus:ring-blue-500/50 focus:border-blue-500 outline-none transition-all placeholder:text-zinc-700 resize-none leading-relaxed custom-scrollbar"
            />
            <button
              onClick={() => onRefresh(idx)}
              disabled={refreshingShots[idx]}
              className={`absolute right-2 top-2.5 p-1.5 text-zinc-600 hover:text-blue-400 hover:bg-blue-400/10 transition-all rounded-md ${refreshingShots[idx] ? 'animate-spin' : ''}`}
              title={t.refreshShot}
            >
              <RefreshCw size={14} />
            </button>
          </div>
        </div>
      ))}
    </div>
  );
};

