export default function App() {
  const [images, setImages] = useState<string[]>([]);
  const [context, setContext] = useState({ english: '', chinese: '' });
  const [contextEditLang, setContextEditLang] = useState<'english' | 'chinese'>('english');
  const [shots, setShots] = useState<StoryboardShot[]>(
    DEFAULT_SHOTS.map((type, idx) => ({ id: idx, type, en: '', cn: '' }))
  );
  const [shotEditLang, setShotEditLang] = useState<'en' | 'cn'>('en');
  const [refreshingShots, setRefreshingShots] = useState<Record<number, boolean>>({});
  const [generatedPrompt, setGeneratedPrompt] = useState<GeneratedPrompt | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [language, setLanguage] = useState<'english' | 'chinese'>('english');
  const [copied, setCopied] = useState(false);
  const [synced, setSynced] = useState(false);
  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const [facingMode, setFacingMode] = useState<VideoFacingModeEnum>('user');

  const fileInputRef = useRef<HTMLInputElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const t = TRANSLATIONS[language];

  useEffect(() => {
    setContextEditLang(language);
    setShotEditLang(language === 'english' ? 'en' : 'cn');
  }, [language]);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;
    Array.from(files).forEach((file: File) => {
      const reader = new FileReader();
      reader.onloadend = () => setImages(prev => [...prev, reader.result as string].slice(0, 5));
      reader.readAsDataURL(file);
    });
    e.target.value = '';
  };

  const removeImage = (index: number) => setImages(prev => prev.filter((_, i) => i !== index));

  const clearAll = () => {
    if (confirm(t.clearConfirm)) {
      setImages([]);
      setContext({ english: '', chinese: '' });
      setGeneratedPrompt(null);
      setShots(DEFAULT_SHOTS.map((type, idx) => ({ id: idx, type, en: '', cn: '' })));
    }
  };

  const startCamera = async (mode: VideoFacingModeEnum = 'user') => {
    setIsCameraOpen(true);
    setFacingMode(mode);
    if (streamRef.current) streamRef.current.getTracks().forEach(track => track.stop());
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: mode } });
      streamRef.current = stream;
      if (videoRef.current) videoRef.current.srcObject = stream;
    } catch (err) {
      setIsCameraOpen(false);
      alert("Camera access denied.");
    }
  };

  const stopCamera = () => {
    if (streamRef.current) streamRef.current.getTracks().forEach(track => track.stop());
    setIsCameraOpen(false);
  };

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(video, 0, 0);
        const dataUrl = canvas.toDataURL('image/jpeg');
        setImages(prev => [...prev, dataUrl].slice(0, 5));
        stopCamera();
      }
    }
  };

  const analyzeImages = async () => {
    if (images.length === 0) return;
    setIsAnalyzing(true);
    try {
      const res = await gemini.analyzeImages(images);
      setContext(res);
    } finally { setIsAnalyzing(false); }
  };

  const handleRefreshShot = async (index: number) => {
    const base = context.english || context.chinese;
    if (!base) return;
    setRefreshingShots(prev => ({ ...prev, [index]: true }));
    try {
      const res = await gemini.suggestShotDescription(base, shots[index].type);
      updateShot(index, { en: res.en, cn: res.cn });
    } finally { setRefreshingShots(prev => ({ ...prev, [index]: false })); }
  };

  const syncToInputs = () => {
    if (!generatedPrompt) return;
    setShots(shots.map((s, i) => ({
      ...s,
      en: generatedPrompt.shotDescriptionsEn[i] || s.en,
      cn: generatedPrompt.shotDescriptionsCn[i] || s.cn
    })));
    setSynced(true);
    setTimeout(() => setSynced(false), 2000);
  };

  const generatePrompt = async () => {
    const base = context.english || context.chinese;
    if (!base) return;
    setIsGenerating(true);
    try {
      const res = await gemini.generateStoryboardPrompt(base, shots);
      setGeneratedPrompt(res);
    } finally { setIsGenerating(false); }
  };

  const updateShot = (index: number, updates: Partial<StoryboardShot>) => {
    const newShots = [...shots];
    newShots[index] = { ...newShots[index], ...updates };
    setShots(newShots);
  };

  const copyToClipboard = () => {
    const text = language === 'english' ? generatedPrompt?.english : generatedPrompt?.chinese;
    if (text) {
      navigator.clipboard.writeText(text);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  return (
    <div className="flex flex-col md:flex-row h-screen overflow-hidden bg-zinc-950 text-zinc-100 selection:bg-blue-500/30">
      {/* Sidebar: Controls */}
      <aside className="w-full md:w-[460px] bg-zinc-950 border-r border-zinc-800/50 flex flex-col overflow-y-auto p-6 gap-8 custom-scrollbar">
        <header className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-blue-600 p-2.5 rounded-2xl shadow-xl shadow-blue-600/20"><Sparkles size={20} className="text-white" /></div>
            <div>
              <h1 className="text-lg font-black tracking-tight leading-tight">{t.appName}</h1>
              <p className="text-[10px] text-zinc-500 uppercase tracking-widest font-black">{t.proGen}</p>
            </div>
          </div>
          <Tooltip content={t.reset} position="left">
            <button onClick={clearAll} className="p-2.5 text-zinc-600 hover:text-red-400 hover:bg-red-400/10 rounded-xl transition-all"><Trash2 size={20} /></button>
          </Tooltip>
        </header>

        {/* Step 1: Reference Images */}
        <section className="space-y-4">
          <div className="flex justify-between items-center">
            <h2 className="text-xs font-black text-zinc-500 uppercase tracking-widest flex items-center gap-2">
              <span className="w-6 h-6 bg-zinc-800 rounded-lg flex items-center justify-center text-[11px] text-zinc-400">01</span> {t.step1Title}
            </h2>
            <div className="flex gap-2">
              <button onClick={() => startCamera('user')} className="text-[10px] font-bold text-zinc-400 hover:text-white bg-zinc-900 px-3 py-1.5 rounded-lg border border-zinc-800 flex items-center gap-2 transition-colors"><Camera size={14} /> {t.camera}</button>
              <span className="text-[10px] font-bold text-zinc-600 bg-zinc-900 px-3 py-1.5 rounded-lg border border-zinc-800 flex items-center">{images.length}/5</span>
            </div>
          </div>
          <div className="grid grid-cols-5 gap-2">
            {images.map((img, idx) => (
              <div key={idx} className="relative aspect-square group rounded-xl overflow-hidden border border-zinc-800 bg-zinc-900 ring-offset-2 ring-offset-zinc-950 hover:ring-2 hover:ring-blue-500 transition-all">
                <img src={img} className="w-full h-full object-cover" />
                <button onClick={() => removeImage(idx)} className="absolute top-1 right-1 p-1 bg-black/60 backdrop-blur-md rounded-lg opacity-0 group-hover:opacity-100 transition-opacity hover:bg-red-500"><X size={12} /></button>
              </div>
            ))}
            {images.length < 5 && (
              <button onClick={() => fileInputRef.current?.click()} className="aspect-square border-2 border-dashed border-zinc-800 rounded-xl flex flex-col items-center justify-center text-zinc-600 hover:bg-zinc-900/50 hover:border-zinc-700 hover:text-zinc-400 transition-all"><Plus size={24} /></button>
            )}
          </div>
          <input type="file" ref={fileInputRef} onChange={handleImageUpload} multiple accept="image/*" className="hidden" />
          <button onClick={analyzeImages} disabled={images.length === 0 || isAnalyzing} className="w-full py-3.5 rounded-2xl flex items-center justify-center gap-2.5 font-bold text-sm transition-all bg-zinc-100 text-zinc-950 hover:bg-white disabled:bg-zinc-900 disabled:text-zinc-700 shadow-lg shadow-white/5 active:scale-95">
            {isAnalyzing ? <RefreshCw className="animate-spin" size={18} /> : <Zap size={18} />} {isAnalyzing ? t.analyzeBtnLoading : t.analyzeBtn}
          </button>
        </section>

        {/* Step 2: Context */}
        <section className="space-y-4">
          <div className="flex justify-between items-center">
            <h2 className="text-xs font-black text-zinc-500 uppercase tracking-widest flex items-center gap-2">
              <span className="w-6 h-6 bg-zinc-800 rounded-lg flex items-center justify-center text-[11px] text-zinc-400">02</span> {t.step2Title}
            </h2>
            <div className="flex bg-zinc-900 p-1 rounded-xl border border-zinc-800">
              <button onClick={() => setContextEditLang('english')} className={`px-3 py-1.5 rounded-lg text-[10px] font-black transition-all ${contextEditLang === 'english' ? 'bg-zinc-700 text-white shadow-sm' : 'text-zinc-500 hover:text-zinc-300'}`}>{t.contextLangEn}</button>
              <button onClick={() => setContextEditLang('chinese')} className={`px-3 py-1.5 rounded-lg text-[10px] font-black transition-all ${contextEditLang === 'chinese' ? 'bg-zinc-700 text-white shadow-sm' : 'text-zinc-500 hover:text-zinc-300'}`}>{t.contextLangCn}</button>
            </div>
          </div>
          <div className="relative group">
            <textarea value={context[contextEditLang]} onChange={e => setContext(prev => ({...prev, [contextEditLang]: e.target.value}))} placeholder={t.textareaPlaceholder} className="w-full h-36 bg-zinc-900 border border-zinc-800 rounded-2xl p-4 text-sm text-zinc-300 resize-none focus:border-blue-500/50 focus:ring-1 focus:ring-blue-500/20 outline-none transition-all leading-relaxed custom-scrollbar" />
            <div className="absolute bottom-3 right-3 opacity-20 pointer-events-none group-focus-within:opacity-50 transition-opacity"><Languages size={18} /></div>
          </div>
        </section>

        {/* Step 3: Shots */}
        <section className="space-y-5">
          <div className="flex justify-between items-center">
            <h2 className="text-xs font-black text-zinc-500 uppercase tracking-widest flex items-center gap-2">
              <span className="w-6 h-6 bg-zinc-800 rounded-lg flex items-center justify-center text-[11px] text-zinc-400">03</span> {t.step3Title}
            </h2>
            <div className="flex bg-zinc-900 p-1 rounded-xl border border-zinc-800">
              <button onClick={() => setShotEditLang('en')} className={`px-3 py-1.5 rounded-lg text-[10px] font-black transition-all ${shotEditLang === 'en' ? 'bg-zinc-700 text-white shadow-sm' : 'text-zinc-500 hover:text-zinc-300'}`}>EN</button>
              <button onClick={() => setShotEditLang('cn')} className={`px-3 py-1.5 rounded-lg text-[10px] font-black transition-all ${shotEditLang === 'cn' ? 'bg-zinc-700 text-white shadow-sm' : 'text-zinc-500 hover:text-zinc-300'}`}>CN</button>
            </div>
          </div>
          <ShotSelector shots={shots} onChange={updateShot} onRefresh={handleRefreshShot} refreshingShots={refreshingShots} language={language} shotEditLang={shotEditLang} t={t} />
          <button onClick={generatePrompt} disabled={(!context.english && !context.chinese) || isGenerating} className="w-full py-4.5 rounded-2xl flex items-center justify-center gap-4 font-black text-sm tracking-[0.1em] transition-all bg-blue-600 hover:bg-blue-500 disabled:bg-zinc-900 disabled:text-zinc-700 shadow-2xl shadow-blue-600/30 active:scale-95 group overflow-hidden relative">
            <div className="absolute inset-0 bg-white/10 translate-y-full group-hover:translate-y-0 transition-transform duration-300"></div>
            {isGenerating ? <RefreshCw className="animate-spin relative z-10" size={20} /> : <LayoutGrid className="relative z-10" size={20} />} 
            <span className="relative z-10">{isGenerating ? t.generateBtnLoading : t.generateBtn}</span>
          </button>
        </section>

        <footer className="mt-auto pt-6 border-t border-zinc-900/50 flex items-center gap-2.5">
          <Info size={14} className="text-zinc-700" />
          <span className="text-[10px] font-bold text-zinc-700 uppercase tracking-widest">{t.footerNote}</span>
        </footer>
      </aside>

      {/* Main Preview Area */}
      <main className="flex-1 flex flex-col p-8 md:p-14 overflow-y-auto bg-zinc-900/40 relative">
        <div className="max-w-4xl mx-auto w-full flex flex-col h-full">
          <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center border-b border-zinc-800/60 pb-10 mb-10 gap-6">
            <div className="space-y-3">
              <h2 className="text-4xl font-black tracking-tighter text-white">{t.masterPrompt}</h2>
              <div className="flex gap-2.5">
                <span className="px-3 py-1 bg-blue-600/10 text-blue-500 border border-blue-500/20 rounded-lg text-[10px] font-black uppercase tracking-widest">{t.consistencyBadge}</span>
                <span className="px-3 py-1 bg-zinc-800/50 text-zinc-400 border border-zinc-800 rounded-lg text-[10px] font-black uppercase tracking-widest">{t.gridBadge}</span>
              </div>
            </div>
            <div className="flex bg-zinc-950 p-2 rounded-2xl border border-zinc-800 shadow-inner ring-1 ring-white/5">
              <button onClick={() => setLanguage('english')} className={`px-6 py-2.5 rounded-xl text-xs font-black transition-all ${language === 'english' ? 'bg-zinc-800 text-white shadow-xl ring-1 ring-white/10' : 'text-zinc-500 hover:text-zinc-300'}`}>ENGLISH</button>
              <button onClick={() => setLanguage('chinese')} className={`px-6 py-2.5 rounded-xl text-xs font-black transition-all ${language === 'chinese' ? 'bg-zinc-800 text-white shadow-xl ring-1 ring-white/10' : 'text-zinc-500 hover:text-zinc-300'}`}>中文</button>
            </div>
