const ShotPreviewIcon: React.FC<{ type: ShotType }> = ({ type }) => {
  const iconProps = { size: 18, className: "text-blue-500/80" };

  // Mapping shot types to visual "hints"
  switch (type) {
    case 'Extreme Close-up':
      return <div className="relative w-full h-full flex items-center justify-center"><Eye {...iconProps} /><div className="absolute inset-0 border-2 border-blue-500/20 m-1 rounded-sm"></div></div>;
    case 'Close-up':
      return <div className="relative w-full h-full flex items-center justify-center scale-125"><User {...iconProps} /></div>;
    case 'Medium Close-up':
      return <div className="relative w-full h-full flex items-center justify-center scale-110"><User {...iconProps} /></div>;
    case 'Medium Shot':
      return <div className="relative w-full h-full flex items-center justify-center"><User {...iconProps} /></div>;
    case 'Medium Full Shot':
      return <div className="relative w-full h-full flex items-center justify-center scale-90"><User {...iconProps} /></div>;
    case 'Full Shot':
      return <div className="relative w-full h-full flex items-center justify-center scale-75"><User {...iconProps} /></div>;
    case 'Wide Shot':
      return <div className="relative w-full h-full flex items-center justify-center"><Mountain {...iconProps} /></div>;
    case 'Extreme Wide Shot':
      return <div className="relative w-full h-full flex items-center justify-center scale-75"><Mountain {...iconProps} /></div>;
    case 'Bird\'s Eye View':
      return <div className="relative w-full h-full flex items-center justify-center"><MoveDown {...iconProps} /><div className="absolute top-1 text-[8px] font-black opacity-40">TOP</div></div>;
    case 'Low Angle Shot':
      return <div className="relative w-full h-full flex flex-col items-center justify-center pt-1"><div className="scale-75"><User {...iconProps} /></div><MoveUp size={10} className="text-blue-400" /></div>;
    case 'High Angle Shot':
      return <div className="relative w-full h-full flex flex-col items-center justify-center pb-1"><MoveDown size={10} className="text-blue-400" /><div className="scale-75"><User {...iconProps} /></div></div>;
    case 'Over the Shoulder':
      return <div className="relative w-full h-full flex items-center justify-center"><div className="absolute left-0 opacity-30 blur-[1px] translate-x-1"><User size={24} /></div><div className="z-10 translate-x-2"><User {...iconProps} /></div></div>;
    case 'POV':
      return <div className="relative w-full h-full flex items-center justify-center"><div className="absolute inset-0 border-[3px] border-blue-500/10 m-1 rounded-full animate-pulse"></div><Camera {...iconProps} /></div>;
    case 'Dutch Angle':
      return <div className="relative w-full h-full flex items-center justify-center rotate-12"><div className="border border-blue-500/30 p-1 rounded-sm"><User {...iconProps} /></div></div>;
    case 'Cowboy Shot':
      return <div className="relative w-full h-full flex items-center justify-center scale-100 translate-y-1"><User {...iconProps} /></div>;
    case 'Two Shot':
      return <div className="relative w-full h-full flex items-center justify-center gap-[-4px]"><Users {...iconProps} /></div>;
    case 'Macro Shot':
      return <div className="relative w-full h-full flex items-center justify-center"><Maximize {...iconProps} /></div>;
    case 'Silhouette Shot':
      return <div className="relative w-full h-full flex items-center justify-center"><div className="bg-blue-500/20 rounded-full p-2"><User size={16} className="text-black" /></div></div>;
    case 'Reflection Shot':
      return <div className="relative w-full h-full flex items-center justify-center gap-1"><div className="opacity-20 blur-[0.5px] -scale-x-100"><User size={14} /></div><div className="w-px h-6 bg-blue-500/30"></div><User {...iconProps} /></div>;
    case 'Profile Shot':
      return <div className="relative w-full h-full flex items-center justify-center"><div className="rotate-90"><User {...iconProps} /></div></div>;
    case 'Establishing Shot':
      return <div className="relative w-full h-full flex items-center justify-center"><Landmark {...iconProps} /></div>;
    default:
      return <HelpCircle {...iconProps} />;
  }
};

